    // For binary strings, this comparison simplifies: A comes before B if A+B > B+A lexicographically.

    const segments = [];
    for (let i = 0; i < nums1.length; i++) {
        const n1 = nums1[i];
        const n0 = nums0[i];
        const segment = {
            s1: n1,
            s0: n0
        };
        segments.push(segment);
    }

