    segments.sort((a, b) => {
        // We need to compare the value of A+B vs B+A.
        // A has s1_a ones and s0_a zeros. B has s1_b ones and s0_b zeros.
        // String A: 1...1 (s1_a times) followed by 0...0 (s0_a times)
        // String B: 1...1 (s1_b times) followed by 0...0 (s0_b times)

        // A+B: (1^s1_a 0^s0_a) + (1^s1_b 0^s0_b)
        // B+A: (1^s1_b 0^s0_b) + (1^s1_a 0^s0_a)

        // Since all segments are composed of contiguous blocks of 1s followed by contiguous blocks of 0s,
        // the lexicographical comparison is equivalent to comparing the resulting binary number.

        // A segment can be represented by its structure (s1, s0).
        // The comparison A+B vs B+A is equivalent to comparing the values:
        // Value(A) * 2^(length(B)) + Value(B)  vs  Value(B) * 2^(length(A)) + Value(A)
        // This is complex because the segments are not single numbers, but structured blocks.

        // Let's use the string comparison approach which is guaranteed to work for lexicographical comparison of concatenated strings.
        // Although we are asked for the integer value, maximizing the integer value is equivalent to maximizing the binary string lexicographically.

        const sA = '1'.repeat(a.s1) + '0'.repeat(a.s0);
        const sB = '1'.repeat(b.s1) + '0'.repeat(b.s0);

        const sAB = sA + sB;
        const sBA = sB + sA;

        // String comparison in JavaScript works lexicographically.
        if (sAB > sBA) {
            return -1; // a should come before b (descending sort based on string value)
        } else if (sAB < sBA) {
            return 1; // b should come before a
        } else {
            return 0;
        }
    });

    // Concatenate the segments in the sorted order
    let finalString = "";
    for (const segment of segments) {
        finalString += '1'.repeat(segment.s1) + '0'.repeat(segment.s0);
    }

