        }

        // result = (result * 2 + bitValue) % modulus
        result = (result * 2n + bitValue) % modulus;
    }

    // Return the result as a standard JavaScript number, as the return type implies a standard integer result based on the problem constraints and modulo operation.
    return Number(result);
