fn solve(nums1: Vec<i64>, nums0: Vec<i64>) -> i64 {
    let n = nums1.len();
    let segments: Vec<(i64, i64)> = (0..n).map(|i| (nums1[i], nums0[i])).collect();

    // Custom comparison logic for sorting segments.
    // Segment A (a1, a0) vs Segment B (b1, b0).
    // A should come before B if AB > BA lexicographically.
    let mut sorted_segments = segments;
    sorted_segments.sort_unstable_by(|&(a1, a0), &(b1, b0)| {
        // String A: 1^a1 0^a0
        // String B: 1^b1 0^b0

        // Constructing the string representation for comparison
        // In Rust, direct string comparison is efficient.
        let s_a = "1".repeat(a1 as usize) + "0".repeat(a0 as usize);
        let s_b = "1".repeat(b1 as usize) + "0".repeat(b0 as usize);

        let s_ab = format!("{}{}", s_a, s_b);
        let s_ba = format!("{}{}", s_b, s_a);

        // We want descending order based on the concatenated string value.
        // If s_ab > s_ba, A should come first, so we return Less.
        s_ba.cmp(&s_ab)
    });

    // Calculate the resulting integer value modulo 10^9 + 7
    let modulus: i128 = 1_000_000_007;
    let mut result: i128 = 0;

    for &(n1, n0) in sorted_segments.iter() {
        // Segment is 1^n1 0^n0. Length is n1 + n0.
        // Value contribution: (2^(n1+n0) - 1) * 2^(number of trailing zeros)

        // The segment 1^n1 0^n0 represents the value (2^n1 - 1) * 2^n0.
        // Let V be the value of this segment.
        // V = (2^n1 - 1) * 2^n0

        // We need to process bit by bit or use modular arithmetic for powers of 2.
        // Since we are appending, we shift the current result by (n1 + n0) bits
        // and then add the value represented by the new segment.

        let len = n1 + n0;

        // 1. Shift current result left by 'len' bits: result = result * 2^len
        // result = (result * 2^len) % modulus
        let power_of_2_len = power(2, len as u64, modulus);
        result = (result * power_of_2_len) % modulus;

        // 2. Add the value of the new segment: V = (2^n1 - 1) * 2^n0
        // V = 2^(n1 + n0) - 2^n0

        // Calculate 2^(n1+n0) mod M
        let two_pow_len = power(2, len as u64, modulus);

        // Calculate 2^n0 mod M
        let two_pow_n0 = power(2, n0 as u64, modulus);

        // Calculate 2^n1 mod M
        let two_pow_n1 = power(2, n1 as u64, modulus);

        // Value V = (2^n1 - 1) * 2^n0 mod M
        // 2^n1 - 1 mod M = (two_pow_n1 - 1 + M) % M
        let two_pow_n1_minus_1 = (two_pow_n1 + modulus - 1) % modulus;

        // V = (two_pow_n1_minus_1 * two_pow_n0) % M
        let segment_value = (two_pow_n1_minus_1 * two_pow_n0) % modulus;

        // Add segment value to result
        result = (result + segment_value) % modulus;
    }

    result as i64
}

// Helper function for modular exponentiation: (base^exp) % modulus
fn power(base: i128, exp: u64, modulus: i128) -> i128 {
    let mut res = 1;
    let mut b = base % modulus;
    let mut e = exp;

    while e > 0 {
        if e % 2 == 1 {
            res = (res * b) % modulus;
        }
        b = (b * b) % modulus;
        e /= 2;
    }
    res
}
